"""Загрузка и сохранение реестра моделей из/в JSON-файл. Один источник правды: store.data."""from __future__ import annotationsimport jsonfrom datetime import datetimefrom pathlib import Pathfrom ..module import ModuleConfigStoreclass LLMModelStore:    """    Хранилище реестра: одна переменная data (dict[key, record]), где key = provider@name.    По умолчанию путь к файлу берётся из ModuleConfigStore (models_store_file).    В конструктор можно передать альтернативный путь к файлу.    """    def __init__(self, store_file_path: Path | str | None = None) -> None:        if store_file_path is not None:            self.store_file_path = Path(store_file_path).resolve()        else:            self.store_file_path = ModuleConfigStore.get().models_store_file        self.data: dict[str, dict] = {}    @staticmethod    def _serialize_value(obj: object) -> object:        """Рекурсивно приводит значения к JSON-сериализуемому виду (datetime -> ISO строка)."""        if isinstance(obj, datetime):            return obj.isoformat()        if isinstance(obj, dict):            return {k: LLMModelStore._serialize_value(v) for k, v in obj.items()}        if isinstance(obj, list):            return [LLMModelStore._serialize_value(v) for v in obj]        return obj    @staticmethod    def _record_key(item: dict) -> str | None:        """Ключ записи: provider@name. None если provider или name пустые."""        provider = item.get("provider") or item.get("provider_code")        name = item.get("name") or item.get("code")        if provider is None or name is None:            return None        p = str(provider).strip()        n = str(name).strip()        if not p or not n:            return None        return f"{p}@{n}"    def load(self) -> None:        """Читает store_file_path и записывает результат в self.data."""        path = self.store_file_path        try:            if not path.exists():                self.data = {}                return            raw = path.read_text(encoding="utf-8").strip()            parsed = json.loads(raw) if raw else {}        except (json.JSONDecodeError, OSError):            self.data = {}            return        if isinstance(parsed, dict):            normalized: dict[str, dict] = {}            for key, item in parsed.items():                if not isinstance(item, dict):                    continue                item_key = self._record_key(item)                use_key = item_key or str(key).strip()                if not use_key:                    continue                normalized[use_key] = item            self.data = normalized            return        self.data = {}    def save(self) -> None:        """Записывает self.data в store_file_path; создаёт каталог при необходимости."""        path = self.store_file_path        path.parent.mkdir(parents=True, exist_ok=True)        payload = self._serialize_value(self.data)        path.write_text(            json.dumps(payload, ensure_ascii=False, indent=2),            encoding="utf-8",        )__all__ = ["LLMModelStore"]